// Extrai dados do webhook POST do WhatsApp Cloud API
const body = $input.first().json.body;

if (!body || !body.entry || !body.entry[0]) {
  return [{ json: { valid: false, reason: 'no_entry' } }];
}

const change = body.entry[0]?.changes?.[0];

// Só processar campo "messages"
if (!change || change.field !== 'messages') {
  return [{ json: { valid: false, reason: 'not_messages_field' } }];
}

const value = change.value;
const metadata = value?.metadata;

if (!metadata) {
  return [{ json: { valid: false, reason: 'no_metadata' } }];
}

const phone_number_id = metadata.phone_number_id;
const display_phone = metadata.display_phone_number;

// Status updates (entrega/leitura) — não são mensagens
if (value.statuses && value.statuses.length > 0 && (!value.messages || value.messages.length === 0)) {
  return [{ json: { valid: false, reason: 'status_update' } }];
}

const messages = value.messages;
if (!messages || messages.length === 0) {
  return [{ json: { valid: false, reason: 'no_messages' } }];
}

const message = messages[0];
const contact = value.contacts?.[0];
const sender_phone = message.from;
const sender_name = contact?.profile?.name || sender_phone;
const message_id = message.id;
const timestamp = message.timestamp;
const message_type = message.type;

let message_body = '';
let media_id = '';

if (message_type === 'text') {
  message_body = message.text?.body || '';
} else if (message_type === 'audio') {
  media_id = message.audio?.id || '';
  message_body = '[ÁUDIO]';
} else if (message_type === 'image') {
  media_id = message.image?.id || '';
  message_body = message.image?.caption || '[IMAGEM]';
} else if (message_type === 'document') {
  media_id = message.document?.id || '';
  message_body = message.document?.caption || '[DOCUMENTO]';
} else if (message_type === 'sticker') {
  message_body = '[FIGURINHA]';
} else if (message_type === 'location') {
  const loc = message.location;
  message_body = `[LOCALIZAÇÃO: lat=${loc?.latitude}, lon=${loc?.longitude}]`;
} else if (message_type === 'button') {
  message_body = message.button?.text || '[BOTÃO]';
} else if (message_type === 'interactive') {
  const interactive = message.interactive;
  if (interactive?.type === 'button_reply') {
    message_body = interactive.button_reply?.title || '[RESPOSTA BOTÃO]';
  } else if (interactive?.type === 'list_reply') {
    message_body = interactive.list_reply?.title || '[RESPOSTA LISTA]';
  } else {
    message_body = '[INTERATIVO]';
  }
} else {
  message_body = `[${message_type.toUpperCase()}]`;
}

return [{
  json: {
    valid: true,
    phone_number_id,
    display_phone,
    sender_phone,
    sender_name,
    message_id,
    timestamp,
    message_type,
    message_body,
    media_id,
    redis_key: `secretaria:msg:${phone_number_id}:${sender_phone}`
  }
}];

// Verifica se a mensagem é para retomar a IA
const contato = $('Buscar Contato').first().json[0];
const msg = $('Montar Contexto Tenant').first().json.message_body.toLowerCase().trim();

const frases_retomar = [
  'atendimento finalizado',
  'finalizar atendimento',
  'retomar ia',
  'ativar ia',
  'ligar ia'
];

const retomar = frases_retomar.some(f => msg.includes(f));

return [{
  json: {
    retomar,
    phone: contato.phone,
    user_id: $('Montar Contexto Tenant').first().json.user_id,
    ...($('Montar Contexto Tenant').first().json)
  }
}];

// Analisa resposta do LGPD
const msg = $('Montar Contexto Tenant').first().json.message_body.toLowerCase().trim();

const aceite = ['sim', 's', 'aceito', 'aceitar', 'concordo', 'ok', 'claro', 'pode', 'tudo bem', 'yes', '1'];
const recusa = ['não', 'nao', 'n', 'recuso', 'recusar', 'não concordo', 'no', '2'];

const respondeu_sim = aceite.some(p => msg === p || msg.startsWith(p + ' '));
const respondeu_nao = recusa.some(p => msg === p || msg.startsWith(p + ' '));

return [{ json: { respondeu_sim, respondeu_nao, msg_original: msg } }];

// Verifica se mensagem está completa (sem novas mensagens no último 1s)
const mem1 = $('Redis GET Memória 1').first().json.value || '';
const mem2 = $('Redis GET Memória 2').first().json.value || '';
const ctx = $('Montar Contexto Tenant').first().json;

// Se mem1 == mem2, nenhuma mensagem nova chegou durante o wait → processar
// Se diferente, uma nova mensagem chegou → skip (ela será processada)
const is_complete = mem1 === mem2;
const mensagem_final = mem2 || ctx.message_body;

return [{
  json: {
    is_complete,
    mensagem_final,
    ...ctx
  }
}];

// Monta o prompt do Gerente de Setores
const ctx = $('Verificar Buffer Completo').first().json;
const contato = $('Buscar Contato Atualizado').first().json[0] || {};

const prompt_gerente = `Você é o gerente de atendimento de um consultório de nutrição.
Classifique esta mensagem em um dos setores abaixo.

=== CONTATO ===
Nome: ${contato.nome || 'Desconhecido'}
Status: ${contato.status || 'LEAD'}
Etiqueta atual: ${contato.etiqueta || 'NOVO_LEAD'}
Histórico resumido: ${contato.resumo_historico || 'Primeiro contato'}

=== MENSAGEM ===
${ctx.mensagem_final}

=== SETORES DISPONÍVEIS ===
- RECEPCAO: Novos leads, dúvidas gerais, agendamentos, apresentação do consultório
- ACOMPANHAMENTO: Pacientes ativos com dúvidas sobre plano alimentar, retorno, evolução
- PRECO: Perguntas sobre valores, planos, investimentos (NUNCA revelar preços, escaldar p/ PRECO)
- HUMANO: Situações urgentes, emergências, reclamações, pedidos explícitos de falar com humano
- EXAME: Envio ou dúvidas sobre exames de sangue, laudos médicos, resultados
- FOLLOWUP: Mensagens de follow-up de leads que não agendaram

=== REGRA IMPORTANTE ===
Paciente ATIVO perguntando sobre upgrade/outros planos → HUMANO (não PRECO)
Mensagens com: ${ctx.palavras_escalar || 'urgente,emergência,dor forte'} → HUMANO

Responda APENAS com JSON válido: {"setor": "NOME_SETOR", "motivo": "breve justificativa"}`;

return [{
  json: {
    prompt_gerente,
    contato,
    ...ctx
  }
}];

// Parseia resposta do gerente e prepara dados para roteamento
let resposta_raw = $json.choices[0].message.content;
let routing;
try {
  routing = JSON.parse(resposta_raw);
} catch(e) {
  routing = { setor: 'RECEPCAO', motivo: 'fallback' };
}

const ctx = $('Verificar Buffer Completo').first().json;
const contato = $('Buscar Contato Atualizado').first().json[0] || {};

// Mapeia etiqueta pelo setor
const etiqueta_map = {
  RECEPCAO: 'EM_ATENDIMENTO_IA',
  ACOMPANHAMENTO: 'EM_ATENDIMENTO_IA',
  PRECO: 'AGUARDANDO_PRECO',
  HUMANO: 'AGUARDANDO_HUMANO',
  EXAME: 'EM_ATENDIMENTO_IA',
  FOLLOWUP: 'FOLLOW_UP_PENDENTE'
};

return [{
  json: {
    setor: routing.setor || 'RECEPCAO',
    motivo_setor: routing.motivo || '',
    etiqueta_nova: etiqueta_map[routing.setor] || 'EM_ATENDIMENTO_IA',
    contato,
    ...ctx
  }
}];

