// Prepara notificação de escalada para humano
const ctx = $('Parser Gerente').first().json;
const contato = ctx.contato;

return [{
  json: {
    output: `⚠️ Solicitação de atendimento humano\nCliente: ${contato.nome || ctx.sender_phone}\nTelefone: ${ctx.sender_phone}\nÚltima mensagem: ${ctx.mensagem_final}`,
    notif: {
      user_id: ctx.user_id,
      phone: ctx.sender_phone,
      nome_contato: contato.nome || ctx.sender_phone,
      motivo: ctx.motivo_setor || 'Solicitação de atendimento humano',
      prioridade: 'ALTA',
      mensagem: ctx.mensagem_final
    },
    ...ctx
  }
}];

// Normaliza output de qualquer agente/resposta para o campo 'output'
const item = $input.first().json;

// Os agentes Langchain retornam em 'output'
// Os Set nodes já têm 'output'
// Garantir que sempre temos 'output'
const output = item.output || item.text || item.response || 'Desculpe, ocorreu um erro. Por favor, tente novamente.';

const ctx = $('Parser Gerente').first().json;

return [{
  json: {
    output: output.trim(),
    user_id: ctx.user_id,
    sender_phone: ctx.sender_phone,
    wa_phone_number_id: ctx.wa_phone_number_id,
    wa_access_token: ctx.wa_access_token,
    mensagem_final: ctx.mensagem_final,
    setor: ctx.setor
  }
}];

// Remove código 251213 e split em partes para envio
const item = $input.first().json;
let texto = item.output.replace(/251213/g, '').trim();

// Split por dupla quebra de linha
const partes = texto.split(/\n\n+/).filter(p => p.trim().length > 0);

// Limitar tamanho de cada parte (WhatsApp: 4096 chars mas ideal < 1000)
const mensagens = [];
const MAX = 1000;

for (const parte of partes) {
  if (parte.length <= MAX) {
    mensagens.push(parte.trim());
  } else {
    // Quebra por frases
    const frases = parte.split(/(?<=[.!?])\s+/);
    let atual = '';
    for (const frase of frases) {
      if ((atual + ' ' + frase).length <= MAX) {
        atual = (atual + ' ' + frase).trim();
      } else {
        if (atual) mensagens.push(atual);
        atual = frase;
      }
    }
    if (atual) mensagens.push(atual);
  }
}

if (mensagens.length === 0) mensagens.push(texto);

// Retorna uma linha por mensagem para o SplitInBatches
return mensagens.map((msg, i) => ({
  json: {
    mensagem_texto: msg,
    parte: i + 1,
    total_partes: mensagens.length,
    sender_phone: item.sender_phone,
    wa_phone_number_id: item.wa_phone_number_id,
    wa_access_token: item.wa_access_token,
    user_id: item.user_id,
    setor: item.setor,
    mensagem_original: item.mensagem_final
  }
}));
